// ---- Passing arguments with Navigation ----

// ---- Define routes with arguments ----
sealed class Screen(val route: String) {
    object Home : Screen("home")
    object Profile : Screen("profile")
    object Detail : Screen("detail/{itemId}") {
        fun pass(itemId: String) = "detail/$itemId"
    }
    object UserDetail : Screen("user/{userId}/edit") {
        fun pass(userId: Int) = "user/$userId/edit"
    }
}

// ---- NavHost with arguments ----
@Composable
fun ArgumentNavigation() {
    val navController = rememberNavController()

    NavHost(
        navController = navController,
        startDestination = Screen.Home.route
    ) {
        composable(Screen.Home.route) {
            HomeScreen(
                onNavigateToDetail = { itemId ->
                    navController.navigate(Screen.Detail.pass(itemId))
                },
                onNavigateToUser = { userId ->
                    navController.navigate(Screen.UserDetail.pass(userId))
                }
            )
        }

        // ---- String argument ----
        composable(
            route = Screen.Detail.route,
            arguments = listOf(
                navArgument("itemId") { type = NavType.StringType }
            )
        ) { backStackEntry ->
            val itemId = backStackEntry.arguments?.getString("itemId") ?: "Unknown"
            DetailScreen(
                itemId = itemId,
                onBack = { navController.popBackStack() }
            )
        }

        // ---- Int argument ----
        composable(
            route = Screen.UserDetail.route,
            arguments = listOf(
                navArgument("userId") { type = NavType.IntType }
            )
        ) { backStackEntry ->
            val userId = backStackEntry.arguments?.getInt("userId") ?: 0
            UserDetailScreen(
                userId = userId,
                onBack = { navController.popBackStack() }
            )
        }
    }
}

// ---- Home Screen ----
@Composable
