    NavHost(navController, startDestination = "home") {
        // 1. Wrong argument type
        composable(
            route = "detail/{id}",
            arguments = listOf(
                navArgument("id") { type = NavType.IntType }
            )
        ) { backStackEntry ->
            val id = backStackEntry.arguments?.getString("id")  // Wrong!
            Text("ID: $id")
        }

        // 2. Not handling null
        composable(
            route = "user/{userId}",
            arguments = listOf(
                navArgument("userId") { type = NavType.IntType }
            )
        ) { backStackEntry ->
            val userId = backStackEntry.arguments?.getInt("userId")!!  // Crashes!
            Text("User: $userId")
        }

        // 3. Mismatched route and args
        composable(
            route = "item/{itemId}/edit",
            arguments = listOf(
                navArgument("itemId") { type = NavType.StringType }
            )
        ) { backStackEntry ->
            // itemId may be missing
            val itemId = backStackEntry.arguments?.getString("itemId")
            Text("Item: $itemId")
        }

        // 4. Navigating with wrong type
        Button(onClick = {
            navController.navigate("detail/abc")  // Int expected but String passed
        }) {
            Text("Go")
        }
    }
